using Microsoft.Data.SqlClient;
using System.Data;
using KmgAssets.Models;

namespace KmgAssets.Services;

public sealed class AssetRepository
{
    private readonly string _connectionString;

    public AssetRepository(string connectionString) => _connectionString = connectionString;

    public async Task<List<Asset>> GetAllAsync(CancellationToken ct = default)
    {
        const string sql = "SELECT Id, Name, Department, Status FROM dbo.Assets ORDER BY Name";
        var list = new List<Asset>();

        await using var conn = new SqlConnection(_connectionString);
        await conn.OpenAsync(ct);
        await using var cmd = new SqlCommand(sql, conn);
        await using var reader = await cmd.ExecuteReaderAsync(ct);

        while (await reader.ReadAsync(ct))
        {
            list.Add(new Asset
            {
                Id         = reader.GetInt32(0),
                Name       = reader.GetString(1),
                Department = reader.GetString(2),
                Status     = reader.GetString(3),
            });
        }
        return list;
    }

    public async Task<int> AddAsync(Asset a, CancellationToken ct = default)
    {
        const string sql = """
            INSERT INTO dbo.Assets (Name, Department, Status)
            OUTPUT INSERTED.Id
            VALUES (@name, @dep, @status)
        """;

        await using var conn = new SqlConnection(_connectionString);
        await conn.OpenAsync(ct);
        await using var cmd = new SqlCommand(sql, conn);
        cmd.Parameters.Add("@name",   SqlDbType.NVarChar, 100).Value = a.Name;
        cmd.Parameters.Add("@dep",    SqlDbType.NVarChar,  50).Value = a.Department;
        cmd.Parameters.Add("@status", SqlDbType.NVarChar,  20).Value = a.Status;
        return (int)(await cmd.ExecuteScalarAsync(ct))!;
    }

    public async Task UpdateAsync(Asset a, CancellationToken ct = default)
    {
        const string sql = """
            UPDATE dbo.Assets
            SET Name=@name, Department=@dep, Status=@status
            WHERE Id=@id
        """;

        await using var conn = new SqlConnection(_connectionString);
        await conn.OpenAsync(ct);
        await using var cmd = new SqlCommand(sql, conn);
        cmd.Parameters.Add("@id",     SqlDbType.Int).Value = a.Id;
        cmd.Parameters.Add("@name",   SqlDbType.NVarChar, 100).Value = a.Name;
        cmd.Parameters.Add("@dep",    SqlDbType.NVarChar,  50).Value = a.Department;
        cmd.Parameters.Add("@status", SqlDbType.NVarChar,  20).Value = a.Status;
        await cmd.ExecuteNonQueryAsync(ct);
    }

    public async Task DeleteAsync(int id, CancellationToken ct = default)
    {
        const string sql = "DELETE FROM dbo.Assets WHERE Id=@id";
        await using var conn = new SqlConnection(_connectionString);
        await conn.OpenAsync(ct);
        await using var cmd = new SqlCommand(sql, conn);
        cmd.Parameters.Add("@id", SqlDbType.Int).Value = id;
        await cmd.ExecuteNonQueryAsync(ct);
    }
}

// MauiProgram.cs
builder.Services.AddSingleton<AssetRepository>(sp =>
{
    var cs = Preferences.Default.Get(
        "DbConnectionString",
        "Server=localhost\\SQLEXPRESS;Database=KmgAssets;Integrated Security=True;TrustServerCertificate=True;"
    );
    return new AssetRepository(cs);
});
builder.Services.AddTransient<AssetsPageVM>();
builder.Services.AddTransient<AssetsPage>();

// ViewModels/AssetsPageVM.cs
public partial class AssetsPageVM : ObservableObject
{
    private readonly AssetRepository _repo;
    private List<Asset> _all = new();

    public AssetsPageVM(AssetRepository repo) => _repo = repo;

    public ObservableCollection<Asset> Filtered { get; } = new();

    [ObservableProperty]
    private string _searchText = string.Empty;

    [ObservableProperty]
    private bool _isBusy;

    partial void OnSearchTextChanged(string value) => ApplyFilter();

    [RelayCommand]
    private async Task LoadAsync()
    {
        try
        {
            IsBusy = true;
            _all = await _repo.GetAllAsync();
            ApplyFilter();
        }
        catch (SqlException ex)
        {
            await Shell.Current.DisplayAlert("Ошибка БД", ex.Message, "OK");
        }
        finally { IsBusy = false; }
    }

    [RelayCommand]
    private async Task DeleteAsync(Asset asset)
    {
        await _repo.DeleteAsync(asset.Id);
        _all.Remove(asset);
        Filtered.Remove(asset);
    }

    private void ApplyFilter()
    {
        var q = SearchText?.Trim() ?? string.Empty;
        Filtered.Clear();
        var query = string.IsNullOrEmpty(q)
            ? _all
            : _all.Where(a => a.Name.Contains(q, StringComparison.OrdinalIgnoreCase));
        foreach (var item in query) Filtered.Add(item);
    }
}
